{
  "prospect": {
    "name": "Carlos R.",
    "company": "BrewLab",
    "role": "Founder"
  },
  "sections": {
    "context": [
      "Walk me through what your team does today.",
      "How did you find me?"
    ],
    "pain": [
      "What's slowing you down most this quarter?",
      "Tell me about the last time it broke."
    ],
    "success_criteria": [
      "What would 'done' look like in 90 days?",
      "How will you measure it?"
    ],
    "budget_signals": [
      "What are you spending on this today?",
      "What budget have you allocated?"
    ],
    "decision_process": [
      "Who else weighs in?",
      "What's your timeline to start?"
    ]
  },
  "scorecard": {
    "fit": 4,
    "urgency": 4,
    "budget": 3,
    "decision_power": 5,
    "vibes": 4,
    "total": 20
  },
  "proposal_seed": {
    "problem": "BrewLab loses 6h/week reconciling SKU spreadsheets.",
    "approach": "Replace manual reconciliation with Airtable + automation; 2 weeks build.",
    "scope": "Setup, data migration, 2 trainings.",
    "price": "\u20ac4,500 fixed.",
    "timeline": "Start within 2 weeks; deliver 14 days; 30-day post-launch support."
  },
  "operator_word_share": 0.22
}
